  async updateWithEmail(id, updates) {
    const oldQuote = await this.getById(id);
    const updatedQuote = await this.update(id, updates);
    if (updates.status && updates.status !== oldQuote.status) {
      const items = [];
      if (updates.status === 'validated') {
