    if (settingsError) throw settingsError;
    if (!settings) {
      const date = new Date();
      const year = date.getFullYear();
      const month = String(date.getMonth() + 1).padStart(2, '0');
      const random = Math.floor(Math.random() * 10000).toString().padStart(4, '0');
      return `DEV-${year}${month}-${random}`;
    }
    const currentYear = new Date().getFullYear();
    let counter = settings.quote_number_counter || 0;
    if (settings.quote_number_reset_yearly && settings.quote_number_last_year !== currentYear) {
      counter = 0;
      await supabase.from('quote_settings').update({
        quote_number_counter: 0,
        quote_number_last_year: currentYear
      }).eq('id', settings.id);
    }
    counter += 1;
    await supabase.from('quote_settings').update({
      quote_number_counter: counter
    }).eq('id', settings.id);
    let parts = [];
    if (settings.quote_number_prefix) {
      parts.push(settings.quote_number_prefix);
    }
    if (settings.quote_number_year_format) {
      const yearStr = settings.quote_number_year_format === 'YY' ? String(currentYear).slice(-2) : String(currentYear);
      parts.push(yearStr);
    }
    const counterStr = String(counter).padStart(settings.quote_number_padding || 3, '0');
    parts.push(counterStr);
    return parts.join(settings.quote_number_separator || '-');
  }
